mapper.delete:
DELETE FROM ${target}
WHERE replyNum = #{replyNum}

	OR parentNum = #{replyNum}

mapper.select:
SELECT replyNum, num, r.member_id, name, content, reg_date, profile_photo, parentNum, showReply FROM ${target} r JOIN member2 m ON r.member_id = m.member_id AND block = 0 WHERE parentNum = #{parentNum}
AND ( showReply = 1 OR r.member_id = #{member_id} )
ORDER BY replyNum DESC

SELECT COUNT(DECODE(replyLike, 1, 1)) likeCount,
	   COUNT(DECODE(replyLike, 0, 1)) disLikeCount
FROM ${targetLike}
WHERE replyNum = #{replyNum}

SELECT replyLike
FROM ${targetLike} 
WHERE replyNum = #{replyNum} AND member_id = #{member_id}
